@@ -1,43 +1,58 @@
 package com.zepay.finance;

+import java.math.BigDecimal;
+import java.math.RoundingMode;
 import java.util.Objects;

 public final class Money {

-    private final double amount;     // ← the IEEE-754 sin
+    private final BigDecimal amount;   // exact decimal, scaled per currency
     private final Currency currency;

+    /** Construction MUST pre-scale to the currency's minor-unit precision. */
     public Money(double amount, Currency currency) {
-        this.amount = amount;
+        this(BigDecimal.valueOf(amount), currency);
+    }
+
+    public Money(BigDecimal amount, Currency currency) {
+        Objects.requireNonNull(amount);
+        this.amount = amount.setScale(currency.scale(), RoundingMode.UNNECESSARY);
         this.currency = Objects.requireNonNull(currency);
     }

-    public double amount()    { return amount; }
+    public BigDecimal amount() { return amount; }
     public Currency currency() { return currency; }

-    /** ← Bug #2 lived here. Fixed: exact decimal add, no drift. */
     public Money plus(Money other) {
         if (other.currency != this.currency) {
             throw new IllegalArgumentException(
                 "cannot add " + currency + " to " + other.currency);
         }
-        return new Money(this.amount + other.amount, this.currency);
+        return new Money(this.amount.add(other.amount), this.currency);
     }

     public long toMinorUnits() {
-        return (long) (this.amount * 100.0);
+        // BigDecimal preserves scale, so unscaled value * 10^(2-scale) is exact.
+        return this.amount
+            .movePointRight(currency.scale())
+            .longValueExact();
     }
 }

